        bestAssignIdx := -1
        bestDelta := 0.0
        var savedStates [MAXASSIGNS][]byte
        type SavedState struct {
            Stations   [][...]Station
            ShipIDs    []int
            Cost       float64
            RouteValid bool
        }
        baseCosts := make([]float64, MAXASSIGNS)
        for ai := 0; ai < dispatch.AssignsLen; ai++ {
            baseCosts[ai] = dispatch.Assigns[ai].Cost
        }
        for ai := 0; ai < dispatch.AssignsLen; ai++ {
            assign := &dispatch.Assigns[ai]
            id := total_ship + shipIdx
            ok := assign.AddShip(id, oris[shipIdx], dess[shipIdx])
            if !ok {
                continue
            }
            oldCost := assign.Cost
            assign.GenRoute()
            newCost := assign.Cost
            if newCost >= 0 {
                delta := newCost - oldCost
                if bestAssignIdx == -1 || delta < bestDelta {
                    bestAssignIdx = ai
                    bestDelta = delta
                }
            }
            assign.RemoveShip(id)
            assign.GenRoute()
        }
        if bestAssignIdx != -1 {
            id := total_ship + shipIdx
            assign := &dispatch.Assigns[bestAssignIdx]
            assign.AddShip(id, oris[shipIdx], dess[shipIdx])
            assign.GenRoute()
        } else {
            id := total_ship + shipIdx
            if dispatch.AssignsLen < MAXASSIGNS {
                assign := &dispatch.Assigns[dispatch.AssignsLen]
                ok := assign.AddShip(id, oris[shipIdx], dess[shipIdx])
                if ok {
                    assign.GenRoute()
                    if assign.Cost >= 0 {
                        dispatch.AssignsLen++
                    } else {
                        assign.RemoveShip(id)
                        assign.GenRoute()
                    }
                }
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

